; マップを開いた時に必ず実行されるスクリプト
[initial]

[endinitial]
;===============================================================================
;◆イベント◆

; 初期発生イベント
events = [1, 5, 8, 9, 11, 12, 13, 14, 15, 16, 17, 18]

;-------------------------------------------------------------------------------
*event_1
;[exp] onObjectTrigger

@notice text="Adventurer's Town - Bravetown"

[eventoff]
;-------------------------------------------------------------------------------
*event_2
;[exp] true

[texton]
[マックス]「We can't go back to town now![r]
[if exp='isDemoVersion']The pursuers[else]Blue[endif] will find us, right?」[k]
[textoff]
@walk move=w

[eventoff]
;-------------------------------------------------------------------------------
*event_3
;[exp] true

@delevent
@addevent num=4
@jump storage="main03.scn" target=*trip_1

[eventoff]
;-------------------------------------------------------------------------------
*event_4
;[exp] true

[texton]
[シュバルツ]「Are you saying you're going to turn back here? We must defeat the evildoers!」[k]
[textoff]
@walk move=n

[eventoff]
;-------------------------------------------------------------------------------
*event_5
;[exp] onObjectTrigger

@question title="<y>Will you drink water from the gushing spring?" cancel=true
[if exp='tf.result']
	[if exp='f.fountainForOpeningEvent']
		@eval exp='o.噴水.doDamage = o.グランドヒール.doDamage'
		@eval exp='o.噴水.resultMessage = o.グランドヒール.resultMessage'
		@btcmd name=噴水
		@notice text="Party's HP restored!"
	[else]
		@notice text="I tried drinking it, but it was just water."
	[endif]
[endif]

[eventoff]
;-------------------------------------------------------------------------------
*event_6
;[exp] true

@delevent
@addevent num=7
@jump storage="main03.scn" target=*trip_2

[eventoff]
;-------------------------------------------------------------------------------
*event_7
;[exp] true

[texton]
[シュバルツ]「Sapphire City isn't that far. Go north.」[k]
[textoff]
@walk move=&'game.party.curX == game.party.lastX ? "n" : (game.party.curX < game.party.lastX ? "e" : "w")'

[eventoff]
