*event_10
;[exp] true

[texton]
[テオ]「...No good, let's turn back.」[k]
The road ahead leads to Bravetown.[r]
[if exp='isDemoVersion']Our pursuers[else]Blue[endif] might find us.[k]
[textoff]
@walk turn=n
@walk move=n

[eventoff]
;-------------------------------------------------------------------------------
*event_11
;[exp] onObjectTrigger

@question title="There is a stone monument. Would you like to touch it?"
[eventoff cond='! tf.result']
@se f=period
@eval exp='o.コリンズの森.setWarp(1, 75, "I", "warp")'
@eval exp='o.コリンズの森.setWarp(34, 5, "J", "warp")'
@delevent

[eventoff]
;-------------------------------------------------------------------------------
*event_12
;[exp] onObjectTrigger

@question title="There is a stone monument. Would you like to touch it?"
[eventoff cond='! tf.result']
@se f=period
@eval exp='o.コリンズの森.setWarp(32, 1, "K", "warp")'
@eval exp='o.ランドン渓谷・崖上.setWarp(26, 66, "G", "warp")'
