[eventoff]
;-------------------------------------------------------------------------------
*event_15
;[exp] o.チーム・アマゾネス.interruption == 0 && random < 0.1

; チーム・アマゾネスとの決闘
@jump storage="duel.ks" target=*amazon_encounter

[eventoff]
;-------------------------------------------------------------------------------
*event_16
;[exp] onObjectTrigger

@notice text="Amazoness Fortress"

[eventoff]
;-------------------------------------------------------------------------------
*event_17
;[exp] true

; チーム・アマゾネスとのボス戦闘
@wait time=500 cond='WAY != "n"'
@walk turn=n cond='WAY != "n"'
@eval exp='game.party.lastWalk = "goForward"'
@fg l=valkyrie_yellow left=300 top=60 b
@fg r=bladesman_red left=600 top=80
@wait time=200
[texton w=1]
[name n=Amazoness f=valkyrie_yellow_00]「This is the Amazoness Fort! You look suspicious!」[k]
[name n=Amazoness f=bladesman_red_01]「Everyone! Let's take down these intruders!」[k]
[textoff]
@clf
@monster pos=0 name=グラディエイター
@monster pos=1 name=グラディエイター
@monster pos=2 name=マスターランサー
@monster pos=4 name=マスターランサー
@monster pos=5 name=グラディエイター
@monster pos=6 name=グラディエイター
@monster pos=8 name=スナイパー
@monster pos=9 name=アークメイジ
@monster pos=10 name=アークプリースト
@monster pos=11 name=アークメイジ
@monster pos=12 name=スナイパー
@callbattle gameover=true
@delevent
[texton w=0]
[name n=Amazoness f=valkyrie_yellow_05]「Strong...!」[k]
Team Amazoness saw how strong we were and backed off.[k]
[textoff]
@eval exp='game.party.lastIsTurn = false'
@eval exp='game.onGameRestart()'
@eval exp='game.checkWarp()'

